import React, { useEffect, useRef, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { FiBookOpen, FiChevronDown, FiLogOut, FiRefreshCw, FiSettings, FiLock } from 'react-icons/fi';
import { useUser } from '../../context/UserContext';

interface HeaderProps {
  setIsAuthenticated: (value: boolean) => void;
}

const Header: React.FC<HeaderProps> = ({ setIsAuthenticated }) => {
  const navigate = useNavigate();
  const { userProfile } = useUser();
  const [dropdownOpen, setDropdownOpen] = useState(false);
  const dropdownRef = useRef<HTMLDivElement | null>(null);
  const initial = userProfile.name?.trim()?.charAt(0).toUpperCase() || 'G';

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setDropdownOpen(false);
      }
    };
    window.addEventListener('mousedown', handleClickOutside);
    return () => window.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleLogout = () => {
    setDropdownOpen(false);
    setIsAuthenticated(false);
    localStorage.removeItem('isAuthenticated');
    navigate('/login');
  };

  return (
    <header className="sticky top-0 z-30 bg-white/95 backdrop-blur border-b border-slate-200 shadow-sm">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-20 flex items-center justify-between gap-4">
        <div className="flex items-center gap-3">
          <div className="bg-gradient-to-r from-blue-600 to-indigo-600 p-3 rounded-2xl text-white shadow-lg shadow-blue-500/10">
            <FiBookOpen size={20} />
          </div>
          <div>
            <div className="text-sm font-semibold text-slate-500">AI Career Hub</div>
            <div className="text-lg font-bold text-slate-900">Skill Intelligence</div>
          </div>
        </div>

        <div className="flex items-center gap-3">
          <button
            onClick={() => navigate('/learning-path')}
            className="rounded-full bg-blue-600 px-4 py-2 text-sm font-semibold text-white shadow-sm hover:bg-blue-700 transition"
          >
            My Learning Path
          </button>

          <div className="relative" ref={dropdownRef}>
            <button
              onClick={() => setDropdownOpen((prev) => !prev)}
              className="w-12 h-12 rounded-full bg-slate-900 text-white font-bold shadow-md hover:bg-slate-800 transition"
            >
              {initial}
            </button>

            {dropdownOpen && (
              <div className="absolute right-0 mt-3 w-56 rounded-3xl border border-slate-200 bg-white shadow-xl shadow-slate-300/20 ring-1 ring-slate-200">
                <div className="p-4 border-b border-slate-100">
                  <div className="text-sm font-semibold text-slate-900">{userProfile.name}</div>
                  <div className="text-xs text-slate-500">{userProfile.role}</div>
                </div>
                <button
                  onClick={() => {
                    setDropdownOpen(false);
                    navigate('/profile');
                  }}
                  className="w-full px-4 py-3 text-left text-sm text-slate-700 hover:bg-slate-50 transition"
                >
                  <span className="inline-flex items-center gap-2"><FiSettings /> Profile Settings</span>
                </button>
                <button
                  onClick={() => {
                    setDropdownOpen(false);
                    navigate('/profile');
                  }}
                  className="w-full px-4 py-3 text-left text-sm text-slate-700 hover:bg-slate-50 transition"
                >
                  <span className="inline-flex items-center gap-2"><FiLock /> Change Password</span>
                </button>
                <button
                  onClick={() => {
                    setDropdownOpen(false);
                    setIsAuthenticated(false);
                    localStorage.removeItem('isAuthenticated');
                    navigate('/login');
                  }}
                  className="w-full px-4 py-3 text-left text-sm text-slate-700 hover:bg-slate-50 transition"
                >
                  <span className="inline-flex items-center gap-2"><FiRefreshCw /> Switch Account</span>
                </button>
                <button
                  onClick={handleLogout}
                  className="w-full px-4 py-3 text-left text-sm font-semibold text-red-600 hover:bg-red-50 transition rounded-b-3xl"
                >
                  <span className="inline-flex items-center gap-2"><FiLogOut /> Logout</span>
                </button>
              </div>
            )}
          </div>
        </div>
      </div>
    </header>
  );
};

export default Header;
